fun daysBetweenDates(startYear: Int, startMonth: Int, startDay: Int, endYear: Int, endMonth: Int, endDay: Int): Int {
    // Helper function to check if a year is a leap year
    fun isLeapYear(year: Int): Boolean {
        return (year % 4 == 0 && year % 100 != 0) || (year % 400 == 0)
    }

    // Helper function to get the number of days in a month
    fun daysInMonth(year: Int, month: Int): Int {
        return when (month) {
            1, 3, 5, 7, 8, 10, 12 -> 31
            4, 6, 9, 11 -> 30
            2 -> if (isLeapYear(year)) 29 else 28
            else -> throw IllegalArgumentException("Invalid month: $month")
        }
    }

    // Helper function to calculate the total number of days from the start of the year to the given date
    fun daysFromStartOfYear(year: Int, month: Int, day: Int): Int {
        var totalDays = 0
        for (m in 1 until month) {
            totalDays += daysInMonth(year, m)
        }
        totalDays += day
        return totalDays
    }

    // Calculate the total number of days from the start date to the end date
    val daysFromStart = daysFromStartOfYear(startYear, startMonth, startDay)
    val daysToEnd = daysFromStartOfYear(endYear, endMonth, endDay)

    // Calculate the total number of days in the years between the start and end years
    var totalDaysBetweenYears = 0
    for (year in startYear + 1 until endYear) {
        totalDaysBetweenYears += if (isLeapYear(year)) 366 else 365
    }

    // Return the total number of days
    return daysToEnd - daysFromStart + totalDaysBetweenYears
}

