    println(countCharacters("yLOI2022")) // Output: Triple(4, 1, 3)
    println(countCharacters("IAKIOIOI")) // Output: Triple(0, 0, 8)
    println(countCharacters("1n2s0e1s")) // Output: Triple(4, 4, 0)
}
